The better-auth organization plugin adds `activeOrganizationId` to the session object automatically. Update the `AppContext` interface and `authMiddleware`:

```typescript
export interface AppContext {
  user: Session["user"] | null;
  session: Session["session"] | null; // Now includes activeOrganizationId
}

export const authMiddleware = os.middleware(async ({ context, next }) => {
  if (!context.user || !context.session) {
    throw new ORPCError("UNAUTHORIZED");
  }
  return next({
    context: {
      user: context.user,
      session: context.session,
    },
  });
});

// New: middleware that also requires an active org
export const orgMiddleware = os.middleware(async ({ context, next }) => {
  if (!context.user || !context.session) {
    throw new ORPCError("UNAUTHORIZED");
  }
  const orgId = context.session.activeOrganizationId;
  if (!orgId) {
    throw new ORPCError("BAD_REQUEST", { message: "No active organization" });
  }
  return next({
    context: {
      user: context.user,
      session: context.session,
      organizationId: orgId as string,
    },
  });
});
```

