```typescript
import { createContext, useContext, type ReactNode } from "react";
import { authClient } from "../lib/auth-client";

interface OrgContextType {
  activeOrg: { id: string; name: string; slug: string; logo?: string } | null;
  organizations: Array<{ id: string; name: string; slug: string }>;
  switchOrg: (orgId: string) => Promise<void>;
  isLoading: boolean;
}

const OrgContext = createContext<OrgContextType | undefined>(undefined);

export function OrganizationProvider({ children }: { children: ReactNode }) {
  const { data: activeOrg, isPending: activeLoading } = authClient.useActiveOrganization();
  const { data: orgs, isPending: listLoading } = authClient.useListOrganizations();

  const switchOrg = async (orgId: string) => {
    await authClient.organization.setActive({ organizationId: orgId });
    // TanStack Query caches will auto-invalidate since the session changes
  };

  return (
    <OrgContext.Provider value={{
      activeOrg: activeOrg ?? null,
      organizations: orgs ?? [],
      switchOrg,
      isLoading: activeLoading || listLoading,
    }}>
      {children}
    </OrgContext.Provider>
  );
}

export function useOrganization() {
  const ctx = useContext(OrgContext);
  if (!ctx) throw new Error("useOrganization must be used within OrganizationProvider");
  return ctx;
}
```

