interface ProjectConfig {
  organizationId: string;
}

export function findProjectConfigPath(cwd: string): string {
  // Walk up from cwd to find git root, use that
  // If no git root, use cwd
  return join(gitRoot, ".rudel.json");
}

export function loadProjectConfig(cwd: string): ProjectConfig | null {
  const path = findProjectConfigPath(cwd);
  if (!existsSync(path)) return null;
  return JSON.parse(readFileSync(path, "utf-8")) as ProjectConfig;
}

export function saveProjectConfig(cwd: string, config: ProjectConfig): void {
  const path = findProjectConfigPath(cwd);
  writeFileSync(path, JSON.stringify(config, null, 2) + "\n");
}
