131→/**
132→ * Generate rule-based insights from current data
133→ */
134→export async function getOverviewInsights(
135→	orgId: string,
136→	days = 7,
137→): Promise<Insight[]> {
138→	const org = escapeString(orgId);
139→	const insights: Insight[] = [];
140→
141→	const currentPeriodQuery = `
142→    SELECT
143→      count() as total_sessions,
144→      uniq(user_id) as total_users,
145→      round(avg(actual_duration_min), 2) as avg_duration_min
146→    FROM rudel.session_analytics
147→    WHERE ${buildDateFilter(days)}
148→      AND organization_id = '${org}'
149→  `;
150→
151→	const previousDays = Number(days) * 2;
152→	const previousPeriodQuery = `
153→    SELECT
154→      count() as total_sessions,
155→      uniq(user_id) as total_users,
156→      round(avg(actual_duration_min), 2) as avg_duration_min
157→    FROM rudel.session_analytics
158→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
159→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
160→      AND organization_id = '${org}'
161→  `;
162→
163→	interface PeriodStats {
164→		total_sessions: number;
165→		total_users: number;
166→		avg_duration_min: number;
167→	}
168→
169→	const [currentData, previousData] = await Promise.all([
170→		queryClickhouse<PeriodStats>(currentPeriodQuery),
171→		queryClickhouse<PeriodStats>(previousPeriodQuery),
172→	]);
173→
174→	const current = currentData[0];
175→	const previous = previousData[0] || { total_sessions: 0 };
176→
177→	// Insight 1: Session trend analysis
178→	if (current && previous) {
179→		const sessionChange =
180→			previous.total_sessions > 0
181→				? ((current.total_sessions - previous.total_sessions) /
182→						previous.total_sessions) *
183→					100
184→				: 0;
185→
186→		if (Math.abs(sessionChange) >= 10) {
187→			const direction = sessionChange > 0 ? "up" : "down";
188→			const severity = sessionChange > 0 ? "positive" : "warning";
189→			insights.push({
190→				type: "trend",
191→				severity,
192→				message: `Team activity ${direction} ${Math.abs(sessionChange).toFixed(1)}% this week`,
193→				link: "/dashboard/team",
194→			});
195→		}
196→	}
197→
198→	// Insight 2: Top performer identification
199→	const topPerformerQuery = `
200→    SELECT
201→      user_id,
202→      count() as sessions,
203→      round(sum(actual_duration_min) / 60, 1) as total_hours
204→    FROM rudel.session_analytics
205→    WHERE ${buildDateFilter(days)}
206→      AND organization_id = '${org}'
207→    GROUP BY user_id
208→    ORDER BY sessions DESC
209→    LIMIT 1
210→  `;
211→
212→	const topPerformer = await queryClickhouse<{
213→		user_id: string;
214→		sessions: number;
215→		total_hours: number;
216→	}>(topPerformerQuery);
217→	if (topPerformer.length > 0 && topPerformer[0]) {
218→		const performer = topPerformer[0];
219→		const { getUserMapping } = await import("./user.service.js");
220→		const userMapping = await getUserMapping(orgId, performer.user_id, days);
221→		const displayName =
222→			userMapping?.username || `${performer.user_id.substring(0, 8)}...`;
223→
224→		insights.push({
225→			type: "performer",
226→			severity: "info",
227→			message: `Top contributor: ${displayName} (${performer.sessions} sessions, ${performer.total_hours}h)`,
228→			link: `/dashboard/developers/${performer.user_id}`,
229→		});
230→	}
231→
232→	// Insight 3: Knowledge silos detection
233→	const knowledgeSilosQuery = `
234→    SELECT
235→      project_path,
236→      uniq(user_id) as unique_users,
237→      count() as sessions
238→    FROM rudel.session_analytics
239→    WHERE ${buildDateFilter(30)}
240→      AND organization_id = '${org}'
241→    GROUP BY project_path
242→    HAVING unique_users = 1 AND sessions >= 5
243→    ORDER BY sessions DESC
244→  `;
245→
246→	const silos = await queryClickhouse<{
247→		project_path: string;
248→		unique_users: number;
249→		sessions: number;
250→	}>(knowledgeSilosQuery);
251→	if (silos.length > 0) {
252→		insights.push({
253→			type: "alert",
254→			severity: "warning",
255→			message: `${silos.length} project${silos.length > 1 ? "s" : ""} with only one developer - risk of knowledge silos`,
256→			link: "/dashboard/projects",
257→		});
258→	}
259→
260→	return insights.slice(0, 3);
261→}
