270→/**
271→ * Get team summary with previous period comparison
272→ */
273→export async function getTeamSummaryWithComparison(orgId: string, days = 7) {
274→	const org = escapeString(orgId);
275→	const previousDays = Number(days) * 2;
276→
277→	const currentQuery = `
278→    SELECT
279→      count() as total_sessions,
280→      uniq(user_id) as active_users,
281→      round(avg(actual_duration_min), 2) as avg_duration_min,
282→      round(count() / uniq(user_id), 2) as avg_sessions_per_user
283→    FROM rudel.session_analytics
284→    WHERE ${buildDateFilter(days)}
285→      AND organization_id = '${org}'
286→  `;
287→
288→	const previousQuery = `
289→    SELECT
290→      count() as total_sessions,
291→      uniq(user_id) as active_users,
292→      round(avg(actual_duration_min), 2) as avg_duration_min,
293→      round(count() / uniq(user_id), 2) as avg_sessions_per_user
294→    FROM rudel.session_analytics
295→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
296→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
297→      AND organization_id = '${org}'
298→  `;
299→
300→	const [currentData, previousData] = await Promise.all([
301→		queryClickhouse<TeamSummaryPeriodData>(currentQuery),
302→		queryClickhouse<TeamSummaryPeriodData>(previousQuery),
303→	]);
304→
305→	const defaultPeriod: TeamSummaryPeriodData = {
306→		total_sessions: 0,
307→		active_users: 0,
308→		avg_duration_min: 0,
309→		avg_sessions_per_user: 0,
310→	};
311→
312→	const current = currentData[0] || defaultPeriod;
313→	const previous = previousData[0] || defaultPeriod;
314→
315→	const calculateChange = (curr: number, prev: number) => {
316→		if (!prev || prev === 0) return 0;
317→		return ((curr - prev) / prev) * 100;
318→	};
319→
320→	const changes = {
321→		total_sessions: calculateChange(
322→			current.total_sessions || 0,
323→			previous.total_sessions || 0,
324→		),
325→		active_users: calculateChange(
326→			current.active_users || 0,
327→			previous.active_users || 0,
328→		),
329→		avg_duration_min: calculateChange(
330→			current.avg_duration_min || 0,
331→			previous.avg_duration_min || 0,
332→		),
333→		avg_sessions_per_user: calculateChange(
334→			current.avg_sessions_per_user || 0,
335→			previous.avg_sessions_per_user || 0,
336→		),
337→	};
338→
339→	return { current, previous, changes };
340→}
