363→      countIf(success_score >= 70) as high_quality_sessions
364→    FROM rudel.session_analytics
365→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
366→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
367→      AND organization_id = '${org}'
368→  `;
369→
370→	interface SuccessRateStats {
