495→/**
496→ * Get flexible dimension analysis with optional split-by for stacked charts
497→ */
498→export async function getSessionDimensionAnalysis(
499→	orgId: string,
500→	params: {
501→		days?: number;
502→		dimension: string;
503→		metric: string;
504→		split_by?: string;
505→		limit?: number;
506→		user_id?: string;
507→		project_path?: string;
508→	},
509→) {
510→	const {
511→		days = 7,
512→		dimension,
513→		metric,
514→		split_by,
515→		limit = 10,
516→		user_id,
517→		project_path,
518→	} = params;
519→	const org = escapeString(orgId);
520→	const d = Number(days);
521→	const lim = Number(limit);
522→
523→	// Validate dimension parameter
524→	const validDimensions = [
525→		"user_id",
526→		"project_path",
527→		"repository",
528→		"session_archetype",
529→		"model_used",
530→		"has_commit",
531→		"used_plan_mode",
532→		"used_skills",
533→		"used_slash_commands",
534→		"used_subagents",
535→	];
536→
537→	if (!validDimensions.includes(dimension)) {
538→		throw new Error(`Invalid dimension: ${dimension}`);
539→	}
540→
541→	if (split_by && !validDimensions.includes(split_by)) {
542→		throw new Error(`Invalid split_by dimension: ${split_by}`);
543→	}
544→
545→	// Map metric to SQL expression
546→	const metricExpressions: Record<string, string> = {
547→		session_count: "COUNT(*)",
548→		avg_duration: "round(AVG(actual_duration_min), 2)",
549→		total_duration: "round(SUM(actual_duration_min) / 60, 2)",
550→		avg_interactions: "round(AVG(total_interactions), 2)",
551→		total_interactions: "SUM(total_interactions)",
552→		avg_response_time: "round(AVG(avg_period_sec), 2)",
553→		median_response_time: "round(AVG(median_period_sec), 2)",
554→		avg_tokens: "round(AVG(total_tokens), 0)",
555→		total_tokens: "SUM(total_tokens)",
556→		avg_success_score: "round(AVG(success_score), 2)",
557→		avg_errors: "round(AVG(error_count), 2)",
558→		total_errors: "SUM(error_count)",
559→	};
560→
561→	const metricExpression = metricExpressions[metric];
562→	if (!metricExpression) {
563→		throw new Error(`Invalid metric: ${metric}`);
564→	}
565→
566→	// Map dimension to SQL expression (for computed dimensions)
567→	const dimensionExpressions: Record<string, string> = {
568→		used_skills: "if(length(skills) > 0, 1, 0)",
569→		used_slash_commands: "if(length(slash_commands) > 0, 1, 0)",
570→		used_subagents: "if(length(subagent_types) > 0, 1, 0)",
571→	};
572→
573→	const dimensionExpression = dimensionExpressions[dimension] || dimension;
574→	const splitByExpression = split_by
575→		? dimensionExpressions[split_by] || split_by
576→		: null;
577→
578→	let filters = "";
579→	if (user_id) {
580→		filters += ` AND user_id = '${escapeString(user_id)}'`;
581→	}
582→	if (project_path) {
583→		filters += ` AND project_path = '${escapeString(project_path)}'`;
584→	}
585→
586→	let query: string;
587→
588→	if (split_by) {
589→		query = `
590→      SELECT
591→        ${dimensionExpression} as dimension_value,
592→        ${splitByExpression} as split_value,
593→        ${metricExpression} as metric_value
594→      FROM rudel.session_analytics
595→      WHERE ${buildDateFilter(d)}
596→        AND organization_id = '${org}'
597→        ${filters}
598→      GROUP BY dimension_value, split_value
599→      ORDER BY metric_value DESC
600→    `;
601→	} else {
602→		query = `
603→      SELECT
604→        ${dimensionExpression} as dimension_value,
605→        ${metricExpression} as metric_value
606→      FROM rudel.session_analytics
607→      WHERE ${buildDateFilter(d)}
608→        AND organization_id = '${org}'
609→        ${filters}
610→      GROUP BY dimension_value
611→      ORDER BY metric_value DESC
612→      LIMIT ${lim}
613→    `;
614→	}
615→
616→	interface DimensionRow {
617→		dimension_value: string;
618→		split_value?: string;
619→		metric_value: number;
620→	}
621→
622→	const results = await queryClickhouse<DimensionRow>(query);
623→
624→	if (split_by) {
625→		const grouped = new Map<string, Record<string, number>>();
626→		const totalMetric = new Map<string, number>();
627→
628→		for (const row of results) {
629→			const dimVal = String(row.dimension_value);
630→			const splitVal = String(row.split_value);
631→			const metricVal = Number(row.metric_value);
632→
633→			if (!grouped.has(dimVal)) {
634→				grouped.set(dimVal, {});
635→				totalMetric.set(dimVal, 0);
636→			}
637→
638→			const group = grouped.get(dimVal);
639→			if (group) group[splitVal] = metricVal;
640→			totalMetric.set(dimVal, (totalMetric.get(dimVal) || 0) + metricVal);
641→		}
642→
643→		const finalData = Array.from(grouped.entries())
644→			.map(([dimension_value, split_values]) => ({
645→				dimension_value,
646→				split_values,
647→				_total: totalMetric.get(dimension_value) || 0,
648→			}))
649→			.sort((a, b) => b._total - a._total)
650→			.slice(0, lim)
651→			.map(({ dimension_value, split_values }) => ({
652→				dimension_value,
653→				split_values,
654→			}));
655→
656→		return finalData;
657→	}
658→
659→	return results.map((row) => ({
660→		dimension_value: String(row.dimension_value),
661→		metric_value: Number(row.metric_value),
662→	}));
663→}
