 21→function getCliParams(): { cliCallback: string; state: string } | null {
 22→	const params = new URLSearchParams(window.location.search);
 23→	const cliCallback = params.get("cli_callback");
 24→	const state = params.get("state");
 25→	if (!cliCallback || !state) return null;
 26→	try {
 27→		const url = new URL(cliCallback);
 28→		if (url.hostname !== "127.0.0.1") return null;
 29→	} catch {
 30→		return null;
 31→	}
 32→	return { cliCallback, state };
 33→}
 34→
 35→function App() {
 36→	const { data: session, isPending } = authClient.useSession();
 37→	const [page, setPage] = useState<Page>("login");
 38→	const [cliRedirecting, setCliRedirecting] = useState(false);
 39→	const cliParams = getCliParams();
 40→
 41→	useEffect(() => {
 42→		if (!session || !cliParams || cliRedirecting) return;
 43→		setCliRedirecting(true);
 44→
 45→		fetch("/api/cli-token", { credentials: "include" })
 46→			.then((res) => res.json())
 47→			.then((data: { token: string }) => {
 48→				const redirectUrl = `${cliParams.cliCallback}?token=${encodeURIComponent(data.token)}&state=${encodeURIComponent(cliParams.state)}`;
 49→				window.location.href = redirectUrl;
 50→			});
 51→	}, [session, cliParams, cliRedirecting]);
 52→
 53→	if (isPending) {
 54→		return (
 55→			<div className="flex min-h-screen items-center justify-center">
 56→				<p className="text-muted-foreground">Loading...</p>
 57→			</div>
 58→		);
 59→	}
 60→
 61→	if (cliRedirecting) {
 62→		return (
 63→			<div className="flex min-h-screen items-center justify-center">
 64→				<p className="text-muted-foreground">Completing CLI login...</p>
 65→			</div>
 66→		);
 67→	}
 68→
 69→	if (!session) {
 70→		return (
 71→			<div className="flex min-h-screen items-center justify-center">
 72→				{page === "login" ? (
 73→					<LoginForm onSwitchToSignup={() => setPage("signup")} />
 74→				) : (
 75→					<SignupForm onSwitchToLogin={() => setPage("login")} />
 76→				)}
 77→			</div>
 78→		);
 79→	}
 80→
 81→	return (
 82→		<Routes>
 83→			<Route path="/" element={<Navigate to="/dashboard" replace />} />
 84→			<Route path="/dashboard" element={<DashboardLayout />}>
 85→				<Route index element={<OverviewPage />} />
 86→				<Route path="developers" element={<DevelopersListPage />} />
 87→				<Route path="developers/:userId" element={<DeveloperDetailPage />} />
 88→				<Route path="projects" element={<ProjectsListPage />} />
 89→				<Route path="projects/:projectPath" element={<ProjectDetailPage />} />
 90→				<Route path="sessions" element={<SessionsListPage />} />
 91→				<Route path="sessions/:sessionId" element={<SessionDetailPage />} />
 92→				<Route path="roi" element={<ROIPage />} />
 93→				<Route path="errors" element={<ErrorsPage />} />
 94→				<Route path="learnings" element={<LearningsPage />} />
 95→				<Route path="profile" element={<ProfilePage />} />
 96→			</Route>
 97→			<Route path="*" element={<Navigate to="/dashboard" replace />} />
 98→		</Routes>
 99→	);
100→}
