  6→
  7→const socialProviders: Record<
  8→	string,
  9→	{ clientId: string; clientSecret: string }
 10→> = {};
 11→if (process.env.GOOGLE_CLIENT_ID && process.env.GOOGLE_CLIENT_SECRET) {
